+    #[test]
+    fn inbox_path_pattern_epoch_zero() {
+        // Timestamp at Unix epoch → 1970/01.
+        let ts_secs: i64 = 0;
+        let dt = chrono::DateTime::from_timestamp(ts_secs, 0).unwrap();
+        let y = dt.format("%Y").to_string();
+        let m = dt.format("%m").to_string();
